const parseDate = (cfg) => {
  const { date, utc } = cfg
  if (Array.isArray(date)) {
    if (utc) {
      if (!date.length) {
        return new Date()
      }
      return new Date(Date.UTC.apply(null, date))
    }
    if (date.length === 1) {
      return dayjs(String(date[0])).toDate()
    }
    return new (Function.prototype.bind.apply(Date, [null].concat(date)))()
  }
  return date
}

c.prototype.isBetween = function (a, b, u, i) {
  const dA = d(a)
  const dB = d(b)
  i = i || '()'
  const dAi = i[0] === '('
  const dBi = i[1] === ')'

  return ((dAi ? this.isAfter(dA, u) : !this.isBefore(dA, u)) &&
         (dBi ? this.isBefore(dB, u) : !this.isAfter(dB, u)))
      || ((dAi ? this.isBefore(dA, u) : !this.isAfter(dA, u)) &&
         (dBi ? this.isAfter(dB, u) : !this.isBefore(dB, u)))
}

function offsetFromString(value = '') {
  const offset = value.match(REGEX_VALID_OFFSET_FORMAT)

  if (!offset) {
    return null
  }

  const [indicator, hoursOffset, minutesOffset] = `${offset[0]}`.match(REGEX_OFFSET_HOURS_MINUTES_FORMAT) || ['-', 0, 0]
  const totalOffsetInMinutes = (+hoursOffset * 60) + (+minutesOffset)

  if (totalOffsetInMinutes === 0) {
    return 0
  }

  return indicator === '+' ? totalOffsetInMinutes : -totalOffsetInMinutes
}

const monthDiff = (a, b) => {
  // function from moment.js in order to keep the same result
  if (a.date() < b.date()) return -monthDiff(b, a)
  const wholeMonthDiff = ((b.year() - a.year()) * 12) + (b.month() - a.month())
  const anchor = a.clone().add(wholeMonthDiff, C.M)
  const c = b - anchor < 0
  const anchor2 = a.clone().add(wholeMonthDiff + (c ? -1 : 1), C.M)
  return +(-(wholeMonthDiff + ((b - anchor) / (c ? (anchor - anchor2) :
    (anchor2 - anchor)))) || 0)
}

const expandCharRanges = (str) => {
  let result = '';
  for (let i = 0, l = str.length; i < l; i++) {
    if (i + 2 < l && str[i + 1] === '-' && str.charCodeAt(i) < str.charCodeAt(i + 2)) {
      const start = str.charCodeAt(i);
      const end = str.charCodeAt(i + 2);
      for (let c = start; c <= end; c++) result += String.fromCharCode(c);
      i += 2;
    } else {
      result += str[i];
    }
  }
  return result;
}

